var surah027 = {
  number: 27,
  nameArabic: "an-Naml",
  nameEnglish: "An-Naml",
  meaning: "The Ant",
  totalAyahs: 93,
  ayahs: [
    { number: 1, arabic: "طسٓ ۚ تِلْكَ ءَايَٰتُ ٱلْقُرْءَانِ وَكِتَابٍۢ مُّبِينٍ", transliteration: "Taseen tilka ayatu alqurani wakitabin mubeenin", transliterationB: "Taa-Seeen; tilka Aayaatul Qur-aani wa Kitaabim Mubeen", english: "These are verses of the Qur'an,-a book that makes (things) clear", romanUrdu: "Taa Seen. yeh aayat hain Quran aur kitaab e mubeen ki" },
    { number: 2, arabic: "هُدًۭى وَبُشْرَىٰ لِلْمُؤْمِنِينَ", transliteration: "Hudan wabushra lilmumineena", transliterationB: "Hudanw wa bushraa lil mu'mineen", english: "A guide: and glad tidings for the believers", romanUrdu: "Hidayat aur basharat un iman laney walon ke liye" },
    { number: 3, arabic: "ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَهُم بِٱلْءَاخِرَةِ هُمْ يُوقِنُونَ", transliteration: "Allatheena yuqeemoona alssalata wayutoona alzzakata wahum bialakhirati hum yooqinoona", transliterationB: "Allazeena yuqeemoonas Salaata wa yu'toonaz Zakaata wa hum bil Aakhirati hum yooqinoon", english: "Those who establish regular prayers and give in regular charity, and also have (full) assurance of the hereafter", romanUrdu: "Jo namaz qayam karte aur zakat detey hain, aur phir woh aisey log hain jo aakhirat par poora yaqeen rakhte hain" },
    { number: 4, arabic: "إِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ زَيَّنَّا لَهُمْ أَعْمَٰلَهُمْ فَهُمْ يَعْمَهُونَ", transliteration: "Inna allatheena la yuminoona bialakhirati zayyanna lahum aAAmalahum fahum yaAAmahoona", transliterationB: "Innal lazeena laa yu'mimoona bil Aakhirati zaiyannaa lahum a'maalahum fahum ya'mahoon", english: "As to those who believe not in the Hereafter, We have made their deeds pleasing in their eyes; and so they wander about in distraction", romanUrdu: "Haqeeqat yeh hai ke jo log aakhirat ko nahin maante unke liye humne unke kartooton ko khushnuma bana diya hai, isliye woh bhatakte phir rahey hain" },
    { number: 5, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ لَهُمْ سُوٓءُ ٱلْعَذَابِ وَهُمْ فِى ٱلْءَاخِرَةِ هُمُ ٱلْأَخْسَرُونَ", transliteration: "Olaika allatheena lahum sooo alAAathabi wahum fee alakhirati humu alakhsaroona", transliterationB: "Ulaaa'ikal lazeena lahum sooo'ul 'azaabi wa hum fil Aakhirati humul akhsaroon", english: "Such are they for whom a grievous Penalty is (waiting); and in the Hereafter theirs will be the greatest loss", romanUrdu: "Yeh woh log hain jinke liye buri saza hai aur aakhirat mein yahi sabse zyada khasare (nuksaan) mein rehne waley hain" },
    { number: 6, arabic: "وَإِنَّكَ لَتُلَقَّى ٱلْقُرْءَانَ مِن لَّدُنْ حَكِيمٍ عَلِيمٍ", transliteration: "Wainnaka latulaqqa alqurana min ladun hakeemin AAaleemin", transliterationB: "Wa innaka latulaqqal Qur-aana mil ladun Hakeemin 'Aleem", english: "As to thee, the Qur'an is bestowed upon thee from the presence of one who is wise and all-knowing", romanUrdu: "Aur (aey Muhammad) bila shubah tum yeh Quran ek hakeem o aleem (All-wise and All-knowing) hasti ki taraf se paa rahey ho" },
    { number: 7, arabic: "إِذْ قَالَ مُوسَىٰ لِأَهْلِهِۦٓ إِنِّىٓ ءَانَسْتُ نَارًۭا سَـَٔاتِيكُم مِّنْهَا بِخَبَرٍ أَوْ ءَاتِيكُم بِشِهَابٍۢ قَبَسٍۢ لَّعَلَّكُمْ تَصْطَلُونَ", transliteration: "Ith qala moosa liahlihi innee anastu naran saateekum minha bikhabarin aw ateekum bishihabin qabasin laAAallakum tastaloona", transliterationB: "Iz qaala Moosaa li ahliheee inneee aanastu naaran saaateekum minhaa bikhabarin aw aateekum bishihaabin qabasil la'allakum tastaloon", english: "Behold! Moses said to his family: \"I perceive a fire; soon will I bring you from there some information, or I will bring you a burning brand to light our fuel, that ye may warm yourselves", romanUrdu: "(Inhein us waqt ka qissa sunao) jab Moosa ne apne ghar walon se kaha ke “mujhey ek aag si nazar aayi hai, main abhi ya to wahan se koi khabar lekar aata hoon ya koi angara chun laata hoon taa-ke tum log garam ho sako”" },
    { number: 8, arabic: "فَلَمَّا جَآءَهَا نُودِىَ أَنۢ بُورِكَ مَن فِى ٱلنَّارِ وَمَنْ حَوْلَهَا وَسُبْحَٰنَ ٱللَّهِ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Falamma jaaha noodiya an boorika man fee alnnari waman hawlaha wasubhana Allahi rabbi alAAalameena", transliterationB: "Falammaa jaaa'ahaa noodiya am boorika man finnnnaari wa man hawlahaa wa Subhaanal laahi Rabbil 'aalameen", english: "But when he came to the (fire), a voice was heard: \"Blessed are those in the fire and those around: and glory to Allah, the Lord of the worlds", romanUrdu: "Wahan jo pahuncha to nidaa (awaaz/pukaar) aayi ke “mubarak hai woh jo is aag mein hai aur jo iske maahol mein hai, paak hai Allah sab jahanon ka parwardigar" },
    { number: 9, arabic: "يَٰمُوسَىٰٓ إِنَّهُۥٓ أَنَا ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Ya moosa innahu ana Allahu alAAazeezu alhakeemu", transliterationB: "Yaa Moosaaa innahooo Anal laahul 'Azeezul Hakeem", english: "O Moses! verily, I am Allah, the exalted in might, the wise", romanUrdu: "Aey Moosa, yeh main hoon Allah, zabardast aur daana(All-Wise)" },
    { number: 10, arabic: "وَأَلْقِ عَصَاكَ ۚ فَلَمَّا رَءَاهَا تَهْتَزُّ كَأَنَّهَا جَآنٌّۭ وَلَّىٰ مُدْبِرًۭا وَلَمْ يُعَقِّبْ ۚ يَٰمُوسَىٰ لَا تَخَفْ إِنِّى لَا يَخَافُ لَدَىَّ ٱلْمُرْسَلُونَ", transliteration: "Waalqi AAasaka falamma raaha tahtazzu kaannaha jannun walla mudbiran walam yuAAaqqib ya moosa la takhaf innee la yakhafu ladayya almursaloona", transliterationB: "Wa alqi 'asaak; falammmaa ra aahaa tahtazzu ka annahaa jaaannunw wallaa mudbiranw wa lam yu'aqqib; yaa Moosaa laa takhaf innee laa yakhaafu ladaiyal mursaloon", english: "Now do thou throw thy rod!\" But when he saw it moving (of its own accord) as if it had been a snake, he turned back in retreat, and retraced not his steps: \"O Moses!\" (it was said), \"Fear not: truly, in My presence, those called as messengers have no fear", romanUrdu: "Aur phenk tu zara apni laathi.” Junhi ke Moosa ne dekha laathi saanp(snake) ki tarah bal kha rahi hai to peeth phair kar bhaaga aur peechey mudh kar bhi na dekha. “Aey Moosa, daro nahin, mere huzur Rasool dara nahin karte" },
    { number: 11, arabic: "إِلَّا مَن ظَلَمَ ثُمَّ بَدَّلَ حُسْنًۢا بَعْدَ سُوٓءٍۢ فَإِنِّى غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Illa man thalama thumma baddala husnan baAAda sooin fainnee ghafoorun raheemun", transliterationB: "Illaa man zalama summa baddala husnam ba'da sooo'in fa innee Ghafoorur Raheem", english: "But if any have done wrong and have thereafter substituted good to take the place of evil, truly, I am Oft-Forgiving, Most Merciful", romanUrdu: "Illa yeh ke kisi ne kasoor kiya ho. Phir agar burayi ke baad usne bhalayi se apne fail (amal) ko badal liya to main maaf karne wala meharbaan hoon" },
    { number: 12, arabic: "وَأَدْخِلْ يَدَكَ فِى جَيْبِكَ تَخْرُجْ بَيْضَآءَ مِنْ غَيْرِ سُوٓءٍۢ ۖ فِى تِسْعِ ءَايَٰتٍ إِلَىٰ فِرْعَوْنَ وَقَوْمِهِۦٓ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًۭا فَٰسِقِينَ", transliteration: "Waadkhil yadaka fee jaybika takhruj baydaa min ghayri sooin fee tisAAi ayatin ila firAAawna waqawmihi innahum kanoo qawman fasiqeena", transliterationB: "Wa adkhil yadaka fee jaibika takhruj baidaaa'a min ghairisooo'in feetis'i Aayaatin ilaa Fir'awna wa qawmih; innahum kaanoo qawman faasiqeen", english: "Now put thy hand into thy bosom, and it will come forth white without stain (or harm): (these are) among the nine Signs (thou wilt take) to Pharaoh and his people: for they are a people rebellious in transgression", romanUrdu: "Aur zara apna haath apne girebaan mein to daalo chamakta hua niklega bagair kisi takleef ke, yeh (dono nishaniyan) naw (nine) nishaniyon mein se hain Firoun aur uske qaum ki taraf (le janey ke liye), woh baday badh-kirdaar(wicked) log hain”" },
    { number: 13, arabic: "فَلَمَّا جَآءَتْهُمْ ءَايَٰتُنَا مُبْصِرَةًۭ قَالُوا۟ هَٰذَا سِحْرٌۭ مُّبِينٌۭ", transliteration: "Falamma jaathum ayatuna mubsiratan qaloo hatha sihrun mubeenun", transliterationB: "Falammaa jaaa'at hum Aayaatunaa mubsiratan qaaloo haazaa sihrum mubeen", english: "But when Our Signs came to them, that should have opened their eyes, they said: \"This is sorcery manifest", romanUrdu: "Magar jab hamari khuli khuli nihsaniyan un logon ke samney aayi to unhon ne kaha yeh to khula jaadu hai" },
    { number: 14, arabic: "وَجَحَدُوا۟ بِهَا وَٱسْتَيْقَنَتْهَآ أَنفُسُهُمْ ظُلْمًۭا وَعُلُوًّۭا ۚ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُفْسِدِينَ", transliteration: "Wajahadoo biha waistayqanatha anfusuhum thulman waAAuluwwan faonthur kayfa kana AAaqibatu almufsideena", transliterationB: "Wa jahadoo bihaa wastaiqanat haaa anfusuhum zulmanw-wa 'uluwwaa; fanzur kaifa kaana 'aaqibatul mufsideen", english: "And they rejected those Signs in iniquity and arrogance, though their souls were convinced thereof: so see what was the end of those who acted corruptly", romanUrdu: "Unhon ne sara-sar zulm aur guroor ki raah se in nishaniyon ka inkar kiya, halaanke dil unke qayel (convinced) ho chuke thay. Ab dekhlo ke un mufsidon ka anjaam kaisa hua" },
    { number: 15, arabic: "وَلَقَدْ ءَاتَيْنَا دَاوُۥدَ وَسُلَيْمَٰنَ عِلْمًۭا ۖ وَقَالَا ٱلْحَمْدُ لِلَّهِ ٱلَّذِى فَضَّلَنَا عَلَىٰ كَثِيرٍۢ مِّنْ عِبَادِهِ ٱلْمُؤْمِنِينَ", transliteration: "Walaqad atayna dawooda wasulaymana AAilman waqala alhamdu lillahi allathee faddalana AAala katheerin min AAibadihi almumineena", transliterationB: "Wa laqad aatainaa Daawooda wa sulaimaana 'ilmaa; wa qaalal hamdu lil laahil lazee faddalanaa 'alaa kaseerim min 'ibaadihil mu'mineen", english: "We gave (in the past) knowledge to David and Solomon: And they both said: \"Praise be to Allah, Who has favoured us above many of his servants who believe", romanUrdu: "(Dusri taraf) humne Dawood o Sulaiman ko ilm ata kiya aur unhon ne kaha ke shukar hai us khuda ka jisne humko apne bahut se momin bandon par fazilat ata ki" },
    { number: 16, arabic: "وَوَرِثَ سُلَيْمَٰنُ دَاوُۥدَ ۖ وَقَالَ يَٰٓأَيُّهَا ٱلنَّاسُ عُلِّمْنَا مَنطِقَ ٱلطَّيْرِ وَأُوتِينَا مِن كُلِّ شَىْءٍ ۖ إِنَّ هَٰذَا لَهُوَ ٱلْفَضْلُ ٱلْمُبِينُ", transliteration: "Wawaritha sulaymanu dawooda waqala ya ayyuha alnnasu AAullimna mantiqa alttayri waooteena min kulli shayin inna hatha lahuwa alfadlu almubeenu", transliterationB: "Wa warisa Sulaimaanu Daawooda wa qaala yaaa aiyuhan naasu 'ullimnaa mantiqat tairi wa ooteenaa min kulli shai'in inna haazaa lahuwal fadlul mubeen", english: "And Solomon was David's heir. He said: \"O ye people! We have been taught the speech of birds, and on us has been bestowed (a little) of all things: this is indeed Grace manifest (from Allah)", romanUrdu: "Aur Dawood ka waris sulaiman hua aur usne kaha “logon, humein parindon (birds) ki boliyan sikhayi gayi hain aur humein har tarah ki cheezein di gayi hain, beshak yeh (Allah ka) numaya fazl hai.”" },
    { number: 17, arabic: "وَحُشِرَ لِسُلَيْمَٰنَ جُنُودُهُۥ مِنَ ٱلْجِنِّ وَٱلْإِنسِ وَٱلطَّيْرِ فَهُمْ يُوزَعُونَ", transliteration: "Wahushira lisulaymana junooduhu mina aljinni waalinsi waalttayri fahum yoozaAAoona", transliterationB: "Wa hushira Sulaimaana junooduhoo minal jinni wal insi wattairi fahum yooza'oon", english: "And before Solomon were marshalled his hosts,- of Jinns and men and birds, and they were all kept in order and ranks", romanUrdu: "Sulaiman ke liye Jinn aur Insano aur parindon ke lashkar jama kiye gaye thay aur woh puray zabt (strict discipline) mein rakkhey jatey thay" },
    { number: 18, arabic: "حَتَّىٰٓ إِذَآ أَتَوْا۟ عَلَىٰ وَادِ ٱلنَّمْلِ قَالَتْ نَمْلَةٌۭ يَٰٓأَيُّهَا ٱلنَّمْلُ ٱدْخُلُوا۟ مَسَٰكِنَكُمْ لَا يَحْطِمَنَّكُمْ سُلَيْمَٰنُ وَجُنُودُهُۥ وَهُمْ لَا يَشْعُرُونَ", transliteration: "Hatta itha ataw AAala wadi alnnamli qalat namlatun ya ayyuha alnnamlu odkhuloo masakinakum la yahtimannakum sulaymanu wajunooduhu wahum la yashAAuroona", transliterationB: "hattaaa izaaa ataw 'alaa waadin namli qaalat namlatuny yaaa aiyuhan namlud khuloo masaakinakum laa yahtimannakum Sulaimaanu wa junooduhoo wa hum laa yash'uroon", english: "At length, when they came to a (lowly) valley of ants, one of the ants said: \"O ye ants, get into your habitations, lest Solomon and his hosts crush you (under foot) without knowing it", romanUrdu: "Ek martaba woh unke saath kooch (marching) kar raha tha) yahan tak ke jab yeh sab chuntiyon (ants) ki waadi(valley) mein pahunchey to ek chunti (ant) ne kaha “ Aey chunityon , Apne bilon (holes) mein ghuss jao, kahin aisa na ho ke Sulaiman aur uske lashkar tumhein kuchal daalein aur unhein khabar bhi na ho”" },
    { number: 19, arabic: "فَتَبَسَّمَ ضَاحِكًۭا مِّن قَوْلِهَا وَقَالَ رَبِّ أَوْزِعْنِىٓ أَنْ أَشْكُرَ نِعْمَتَكَ ٱلَّتِىٓ أَنْعَمْتَ عَلَىَّ وَعَلَىٰ وَٰلِدَىَّ وَأَنْ أَعْمَلَ صَٰلِحًۭا تَرْضَىٰهُ وَأَدْخِلْنِى بِرَحْمَتِكَ فِى عِبَادِكَ ٱلصَّٰلِحِينَ", transliteration: "Fatabassama dahikan min qawliha waqala rabbi awziAAnee an ashkura niAAmataka allatee anAAamta AAalayya waAAala walidayya waan aAAmala salihan tardahu waadkhilnee birahmatika fee AAibadika alssaliheena", transliterationB: "Fatabassama daahikam min qawlihaa wa qaala Rabbi awzi'nee an ashkura ni'mata kal lateee an'amta 'alaiya wa 'alaa waalidaiya wa an a'mala saalihan tardaahu wa adkhilnee birahmatika fee 'ibaadikas saaliheen", english: "So he smiled, amused at her speech; and he said: \"O my Lord! so order me that I may be grateful for Thy favours, which thou hast bestowed on me and on my parents, and that I may work the righteousness that will please Thee: And admit me, by Thy Grace, to the ranks of Thy righteous Servants", romanUrdu: "Sulaiman uski baat par muskurate huey hass pada aur bola “aey mere Rubb mujhey qaabu mein rakh ke main tere us ehsan ka shukar ada karta rahoon jo tu-nay mujhpar aur mere walidain par kiya hai aur aisa amal e saleh karoon jo tujhey pasand aaye, aur apni rehmat se mujhko apne saleh bandon mein daakhil kar.”" },
    { number: 20, arabic: "وَتَفَقَّدَ ٱلطَّيْرَ فَقَالَ مَا لِىَ لَآ أَرَى ٱلْهُدْهُدَ أَمْ كَانَ مِنَ ٱلْغَآئِبِينَ", transliteration: "Watafaqqada alttayra faqala ma liya la ara alhudhuda am kana mina alghaibeena", transliterationB: "Wa tafaqqadat taira faqaala maa liya laaa aral hud hud, am kaana minal ghaaa'ibeen", english: "And he took a muster of the Birds; and he said: \"Why is it I see not the Hoopoe? Or is he among the absentees", romanUrdu: "(Ek aur mauqe par) Sulaiman ne parindon ka jaiza liya aur kaha “ kya baat hai ke main falaan hud-hud (hoopoe bird) ko nahin dekh raha hoon. Kya woh kahin gayab ho gaya hai" },
    { number: 21, arabic: "لَأُعَذِّبَنَّهُۥ عَذَابًۭا شَدِيدًا أَوْ لَأَا۟ذْبَحَنَّهُۥٓ أَوْ لَيَأْتِيَنِّى بِسُلْطَٰنٍۢ مُّبِينٍۢ", transliteration: "LaoAAaththibannahu AAathaban shadeedan aw laathbahannahu aw layatiyannee bisultanin mubeenin", transliterationB: "La-u'azzibanahoo 'azaaban shadeedan aw la azbahannahoo aw layaatiyannee bisultaanim mubeen", english: "I will certainly punish him with a severe penalty, or execute him, unless he bring me a clear reason (for absence)", romanUrdu: "Main usey sakht saza dunga, ya zubaa kardunga, warna usey mere saamne maaqool wajah pesh karni hogi" },
    { number: 22, arabic: "فَمَكَثَ غَيْرَ بَعِيدٍۢ فَقَالَ أَحَطتُ بِمَا لَمْ تُحِطْ بِهِۦ وَجِئْتُكَ مِن سَبَإٍۭ بِنَبَإٍۢ يَقِينٍ", transliteration: "Famakatha ghayra baAAeedin faqala ahattu bima lam tuhit bihi wajituka min sabain binabain yaqeenin", transliterationB: "Famakasa ghaira ba'eedin faqaala ahattu bimaa lam tuhit bihee wa ji'tuka min Sabaim binaba iny-yaqeen", english: "But the Hoopoe tarried not far: he (came up and) said: \"I have compassed (territory) which thou hast not compassed, and I have come to thee from Saba with tidings true", romanUrdu: "Kuch zyada dair na guzri thi ke usne aakar kaha “maine woh maalumaat haasil ki hai jo aapke ilam mein nahin hain. Main Saba ke mutaalik yaqeeni ittila lekar aaya hoon" },
    { number: 23, arabic: "إِنِّى وَجَدتُّ ٱمْرَأَةًۭ تَمْلِكُهُمْ وَأُوتِيَتْ مِن كُلِّ شَىْءٍۢ وَلَهَا عَرْشٌ عَظِيمٌۭ", transliteration: "Innee wajadtu imraatan tamlikuhum waootiyat min kulli shayin walaha AAarshun AAatheemun", transliterationB: "Innee wajattum ra atan tamlikuhum wa ootiyat min kulli shai'inw wa lahaa 'arshun 'azeem", english: "I found (there) a woman ruling over them and provided with every requisite; and she has a magnificent throne", romanUrdu: "Maine wahan ek aurat dekhi jo us qaum ki hukmaran hai. Usko har tarah ka saaz o samaan baksha gaya hai aur uska takht (throne) bada azeem o shaan hai" },
    { number: 24, arabic: "وَجَدتُّهَا وَقَوْمَهَا يَسْجُدُونَ لِلشَّمْسِ مِن دُونِ ٱللَّهِ وَزَيَّنَ لَهُمُ ٱلشَّيْطَٰنُ أَعْمَٰلَهُمْ فَصَدَّهُمْ عَنِ ٱلسَّبِيلِ فَهُمْ لَا يَهْتَدُونَ", transliteration: "Wajadtuha waqawmaha yasjudoona lilshshamsi min dooni Allahi wazayyana lahumu alshshaytanu aAAmalahum fasaddahum AAani alssabeeli fahum la yahtadoona", transliterationB: "Wajattuhaa wa qawmahaa yasjudoona lishshamsi min doonil laahi wa zaiyana lahumush Shaitaanu a'maalahum fasaddahum 'anis sabeeli fahum laa yahtadoon", english: "I found her and her people worshipping the sun besides Allah: Satan has made their deeds seem pleasing in their eyes, and has kept them away from the Path,- so they receive no guidance", romanUrdu: "Maine dekha hai ke woh aur uski qaum Allah ke bajaye Suraj ke aagey sajda karti hai” Shaytaan ne unke aamaal unke liye khushnuma bana diye aur unhein shahraah se rok diya, is waja se woh yeh seedha raasta nahin paatey" },
    { number: 25, arabic: "أَلَّا يَسْجُدُوا۟ لِلَّهِ ٱلَّذِى يُخْرِجُ ٱلْخَبْءَ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَيَعْلَمُ مَا تُخْفُونَ وَمَا تُعْلِنُونَ", transliteration: "Alla yasjudoo lillahi allathee yukhriju alkhabaa fee alssamawati waalardi wayaAAlamu ma tukhfoona wama tuAAlinoona", transliterationB: "Allaa yasjudoo lillaahil lazee yukhrijul khab'a fis samaawaati wal ardi wa ya'lamu maa tukhfoona wa maa tu'linoon", english: "(Kept them away from the Path), that they should not worship Allah, Who brings to light what is hidden in the heavens and the earth, and knows what ye hide and what ye reveal", romanUrdu: "Ke us khuda ko sajda karein jo aasmano aur zameen ki posheeda(hidden) cheezein nikalta hai aur woh sab kuch jaanta hai jisey tum log chupate ho aur zaahir karte ho" },
    { number: 26, arabic: "ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ رَبُّ ٱلْعَرْشِ ٱلْعَظِيمِ ۩", transliteration: "Allahu la ilaha illa huwa rabbu alAAarshi alAAatheemi", transliterationB: "Allaahu laaa ilaaha illaa Huwa Rabbul 'Arshil Azeem", english: "Allah!- there is no god but He!- Lord of the Throne Supreme", romanUrdu: "Allah, ke jiske siwa koi mustahiq e Ibadat(worthy of worship) nahin, jo arsh e azeem ka maalik hai" },
    { number: 27, arabic: "۞ قَالَ سَنَنظُرُ أَصَدَقْتَ أَمْ كُنتَ مِنَ ٱلْكَٰذِبِينَ", transliteration: "Qala sananthuru asadaqta am kunta mina alkathibeena", transliterationB: "Qaala sananzuru asadaqta am kunta minal kaazibeen", english: "(Solomon) said: \"Soon shall we see whether thou hast told the truth or lied", romanUrdu: "Sulaiman ne kaha “abhi hum dekhe letay hain ke tu nay sach kaha hai ye tu jhoot bolne walon mein se hai" },
    { number: 28, arabic: "ٱذْهَب بِّكِتَٰبِى هَٰذَا فَأَلْقِهْ إِلَيْهِمْ ثُمَّ تَوَلَّ عَنْهُمْ فَٱنظُرْ مَاذَا يَرْجِعُونَ", transliteration: "Ithhab bikitabee hatha faalqih ilayhim thumma tawalla AAanhum faonthur matha yarjiAAoona", transliterationB: "Izhab bikitaabee haaza fa alqih ilaihim summma tawalla 'anhum fanzur maazaa yarji'oon", english: "Go thou, with this letter of mine, and deliver it to them: then draw back from them, and (wait to) see what answer they return", romanUrdu: "Mera yeh khat (letter) le ja aur usey un logon ki taraf daal de, phir alag hatt kar dekh ke woh kya radd-e-amal zaahir karte hain”" },
    { number: 29, arabic: "قَالَتْ يَٰٓأَيُّهَا ٱلْمَلَؤُا۟ إِنِّىٓ أُلْقِىَ إِلَىَّ كِتَٰبٌۭ كَرِيمٌ", transliteration: "Qalat ya ayyuha almalao innee olqiya ilayya kitabun kareemun", transliterationB: "Qaalat yaaa aiyuhal mala'u innee ulqiya ilaiya kitaabun kareem", english: "(The queen) said: \"Ye chiefs! here is delivered to me - a letter worthy of respect", romanUrdu: "Malika boli “aey ehle darbaar, meri taraf ek bada eham khat phenka gaya hai" },
    { number: 30, arabic: "إِنَّهُۥ مِن سُلَيْمَٰنَ وَإِنَّهُۥ بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ", transliteration: "Innahu min sulaymana wainnahu bismi Allahi alrrahmani alrraheemi", transliterationB: "Innahoo min Sulaimaana wa innahoo bismil laahir Rahmaanir Raheem", english: "It is from Solomon, and is (as follows): 'In the name of Allah, Most Gracious, Most Merciful", romanUrdu: "Woh Sulaiman ki janib se hai aur Allah rehman o raheem ke naam se shuru kiya gaya hai" },
    { number: 31, arabic: "أَلَّا تَعْلُوا۟ عَلَىَّ وَأْتُونِى مُسْلِمِينَ", transliteration: "Alla taAAloo AAalayya watoonee muslimeena", transliterationB: "Allaa ta'loo 'alaiya waa toonee muslimeen", english: "Be ye not arrogant against me, but come to me in submission (to the true Religion)", romanUrdu: "Mazmoon yeh hai ke “ mere muqable mein sarkashi na karo aur muslim ho kar mere paas haazir ho jao”" },
    { number: 32, arabic: "قَالَتْ يَٰٓأَيُّهَا ٱلْمَلَؤُا۟ أَفْتُونِى فِىٓ أَمْرِى مَا كُنتُ قَاطِعَةً أَمْرًا حَتَّىٰ تَشْهَدُونِ", transliteration: "Qalat ya ayyuha almalao aftoonee fee amree ma kuntu qatiAAatan amran hatta tashhadoona", transliterationB: "Qaalat yaaa aiyuhal mala'u aftoonee fee amree maa kuntu qaati'atan amran hattaa tashhhaddon", english: "She said: \"Ye chiefs! advise me in (this) my affair: no affair have I decided except in your presence", romanUrdu: "(khat sunakar) Malika ne kaha “aey sardaran e qaum mere is maamle mein mujhey mashwara do. Main kisi maamle ka faisla tumhare bagair nahin karti hoon”" },
    { number: 33, arabic: "قَالُوا۟ نَحْنُ أُو۟لُوا۟ قُوَّةٍۢ وَأُو۟لُوا۟ بَأْسٍۢ شَدِيدٍۢ وَٱلْأَمْرُ إِلَيْكِ فَٱنظُرِى مَاذَا تَأْمُرِينَ", transliteration: "Qaloo nahnu oloo quwwatin waoloo basin shadeedin waalamru ilayki faonthuree matha tamureena", transliterationB: "Qaaloo nahnu uloo quwwatinw wa uloo baasin shadeed; wal amru ilaiki fanzuree maazaa taamureen", english: "They said: \"We are endued with strength, and given to vehement war: but the command is with thee; so consider what thou wilt command", romanUrdu: "Unhon ne jawab diya “hum taqatwar aur ladne waley log hain, aagey faisla aap ke haath mein hai, aap khud dekh lein ke aapko kya hukum dena hai”" },
    { number: 34, arabic: "قَالَتْ إِنَّ ٱلْمُلُوكَ إِذَا دَخَلُوا۟ قَرْيَةً أَفْسَدُوهَا وَجَعَلُوٓا۟ أَعِزَّةَ أَهْلِهَآ أَذِلَّةًۭ ۖ وَكَذَٰلِكَ يَفْعَلُونَ", transliteration: "Qalat inna almulooka itha dakhaloo qaryatan afsadooha wajaAAaloo aAAizzata ahliha athillatan wakathalika yafAAaloona", transliterationB: "Qaalat innal mulooka izaa dakhaloo qaryatan afsadoohaa wa ja'alooo a'izzata ahlihaaa azillah; wa kazaalika yaf'aloon", english: "She said: \"Kings, when they enter a country, despoil it, and make the noblest of its people its meanest thus do they behave", romanUrdu: "Malika ne kaha ke “Baadshah jab kisi mulk mein ghus aate hain to usey kharab aur uske izzat walon ko zaleel kar detay hain, yahi kuch woh kiya karte hain" },
    { number: 35, arabic: "وَإِنِّى مُرْسِلَةٌ إِلَيْهِم بِهَدِيَّةٍۢ فَنَاظِرَةٌۢ بِمَ يَرْجِعُ ٱلْمُرْسَلُونَ", transliteration: "Wainnee mursilatun ilayhim bihadiyyatin fanathiratun bima yarjiAAu almursaloona", transliterationB: "Wa innee mursilatun ilaihim bihadiyyatin fanaaziratum bima yarji'ul mursaloon", english: "But I am going to send him a present, and (wait) to see with what (answer) return (my) ambassadors", romanUrdu: "Main in logon ki taraf ek hadiya(gift) bhejti hoon, phir dekhti hoon ke mere elchi (envoy) kya jawaab lekar palat-te hain”" },
    { number: 36, arabic: "فَلَمَّا جَآءَ سُلَيْمَٰنَ قَالَ أَتُمِدُّونَنِ بِمَالٍۢ فَمَآ ءَاتَىٰنِۦَ ٱللَّهُ خَيْرٌۭ مِّمَّآ ءَاتَىٰكُم بَلْ أَنتُم بِهَدِيَّتِكُمْ تَفْرَحُونَ", transliteration: "Falamma jaa sulaymana qala atumiddoonani bimalin fama ataniya Allahu khayrun mimma atakum bal antum bihadiyyatikum tafrahoona", transliterationB: "Falammaa jaaa'a Sulaimaana qaala atumiddoonani bimaalin famaaa aataakum bal antum bihadiy yatikum tafrahoon", english: "Now when (the embassy) came to Solomon, he said: \"Will ye give me abundance in wealth? But that which Allah has given me is better than that which He has given you! Nay it is ye who rejoice in your gift", romanUrdu: "Jab woh [Malika ka safeer(envoy)] Sulaiman ke haan pahuncha to usne kaha, “ kya tum log maal se meri madad karna chahte ho? Jo kuch khuda ne mujhey de rakkha hai woh issey bahut zyada hai jo tumhein diya hai. Tumhara hadiya (gifts) tumhi ko mubarak rahey" },
    { number: 37, arabic: "ٱرْجِعْ إِلَيْهِمْ فَلَنَأْتِيَنَّهُم بِجُنُودٍۢ لَّا قِبَلَ لَهُم بِهَا وَلَنُخْرِجَنَّهُم مِّنْهَآ أَذِلَّةًۭ وَهُمْ صَٰغِرُونَ", transliteration: "IrjiAA ilayhim falanatiyannahum bijunoodin la qibala lahum biha walanukhrijannahum minha athillatan wahum saghiroona", transliterationB: "Irji' ilaihim falanaatiyan nahum bijunoodil laa qibala lahum bihaa wa lanukhri jannahum minhaaa azillatanw wa hum saaghiroon", english: "Go back to them, and be sure we shall come to them with such hosts as they will never be able to meet: We shall expel them from there in disgrace, and they will feel humbled (indeed)", romanUrdu: "aey safeer (envoy)]wapas jaa apne bhejne walon ki taraf, hum unpar aisey lashkar lekar aayenge jinka muqabla woh na kar sakenge, aur hum unhein aisi zillat ke saath wahan se nikalenge ke woh khwar hokar reh jayenge”" },
    { number: 38, arabic: "قَالَ يَٰٓأَيُّهَا ٱلْمَلَؤُا۟ أَيُّكُمْ يَأْتِينِى بِعَرْشِهَا قَبْلَ أَن يَأْتُونِى مُسْلِمِينَ", transliteration: "Qala ya ayyuha almalao ayyukum yateenee biAAarshiha qabla an yatoonee muslimeena", transliterationB: "Qaala yaaa aiyuhal mala'u aiyukum yaateenee bi'arshihaa qabla ai yaatoonee muslimeen", english: "He said (to his own men): \"Ye chiefs! which of you can bring me her throne before they come to me in submission", romanUrdu: "Sulaiman ne kaha “aey ehle darbaar, tum mein se kaun uska takht (throne) mere paas laata hai qabl iske ke woh log mutii (farmabardaar) hokar mere paas haazir hoon?”" },
    { number: 39, arabic: "قَالَ عِفْرِيتٌۭ مِّنَ ٱلْجِنِّ أَنَا۠ ءَاتِيكَ بِهِۦ قَبْلَ أَن تَقُومَ مِن مَّقَامِكَ ۖ وَإِنِّى عَلَيْهِ لَقَوِىٌّ أَمِينٌۭ", transliteration: "Qala AAifreetun mina aljinni ana ateeka bihi qabla an taqooma min maqamika wainne AAalayhi laqawiyyun ameenun", transliterationB: "Qaala 'ifreetum minal jinni ana aateeka bihee qabla an taqooma mim maqaamika wa innee 'alaihi laqawiyyun ameen", english: "Said an 'Ifrit, of the Jinns: \"I will bring it to thee before thou rise from thy council: indeed I have full strength for the purpose, and may be trusted", romanUrdu: "Jinno mein se ek qawi (mighty) haykal ne arz kiya “ main usey haazir kardunga qabl iske ke aap apni jagah se utthein. Main iski taaqat rakhta hoon aur amaanatdaar hoon”" },
    { number: 40, arabic: "قَالَ ٱلَّذِى عِندَهُۥ عِلْمٌۭ مِّنَ ٱلْكِتَٰبِ أَنَا۠ ءَاتِيكَ بِهِۦ قَبْلَ أَن يَرْتَدَّ إِلَيْكَ طَرْفُكَ ۚ فَلَمَّا رَءَاهُ مُسْتَقِرًّا عِندَهُۥ قَالَ هَٰذَا مِن فَضْلِ رَبِّى لِيَبْلُوَنِىٓ ءَأَشْكُرُ أَمْ أَكْفُرُ ۖ وَمَن شَكَرَ فَإِنَّمَا يَشْكُرُ لِنَفْسِهِۦ ۖ وَمَن كَفَرَ فَإِنَّ رَبِّى غَنِىٌّۭ كَرِيمٌۭ", transliteration: "Qala allathee AAindahu AAilmun mina alkitabi ana ateeka bihi qabla an yartadda ilayka tarfuka falamma raahu mustaqirran AAindahu qala hatha min fadli rabbee liyabluwanee aashkuru am akfuru waman shakara fainnama yashkuru linafsihi waman kafara fainna rabbee ghaniyyun kareemun", transliterationB: "Qaalal lazee indahoo 'ilmum minal Kitaabi ana aateeka bihee qabla ai yartadda ilaika tarfuk; falammaa ra aahu mustaqirran 'indahoo qaala haazaa min fadli Rabbee li yabluwaneee 'a-ashkuru am akfuru wa man shakara fa innamaa yashkuru linafsihee wa man kafara fa inna Rabbee Ghaniyyun Kareem", english: "Said one who had knowledge of the Book: \"I will bring it to thee within the twinkling of an eye!\" Then when (Solomon) saw it placed firmly before him, he said: \"This is by the Grace of my Lord!- to test me whether I am grateful or ungrateful! and if any is grateful, truly his gratitude is (a gain) for his own soul; but if any is ungrateful, truly my Lord is Free of all Needs, Supreme in Honour", romanUrdu: "Jis shaks ke paas kitaab ka ilam tha woh bola “main aapki palakh jhapakne se pehle usey laye deta hoon”. Junhi ke Sulaiman ne woh takht apne paas rakkha hua dekha, woh pukar uttha “Yeh mere Rub ka fazal hai taa-ke woh mujhey aazmaaye ke main shukar karta hoon ya kaafir e niyamat karta hoon. Aur jo koi shukar karta hai uska shukar uske apne hi liye mufeed hai, warna koi nashukari karey to mera Rubb be-niyaz aur apni zaat mein aap buzurg hai.”" },
    { number: 41, arabic: "قَالَ نَكِّرُوا۟ لَهَا عَرْشَهَا نَنظُرْ أَتَهْتَدِىٓ أَمْ تَكُونُ مِنَ ٱلَّذِينَ لَا يَهْتَدُونَ", transliteration: "Qala nakkiroo laha AAarshaha nanthur atahtadee am takoonu mina allatheena la yahtadoona", transliterationB: "Qaala nakkiroo lahaa 'arshahaa nanzur atahtadeee am takoonu minal lazeena laa yahtadoon", english: "He said: \"Transform her throne out of all recognition by her: let us see whether she is guided (to the truth) or is one of those who receive no guidance", romanUrdu: "Sulaiman ne kaha “anjaan tareeqe se uska takht uske saamne rakh do, dekhein woh saheeh baat tak pahunchti hai ya un logon mein se hai jo raah e raast nahin paatey.”" },
    { number: 42, arabic: "فَلَمَّا جَآءَتْ قِيلَ أَهَٰكَذَا عَرْشُكِ ۖ قَالَتْ كَأَنَّهُۥ هُوَ ۚ وَأُوتِينَا ٱلْعِلْمَ مِن قَبْلِهَا وَكُنَّا مُسْلِمِينَ", transliteration: "Falamma jaat qeela ahakatha AAarshuki qalat kaannahu huwa waooteena alAAilma min qabliha wakunna muslimeena", transliterationB: "Falammaa jaaa'at qeela ahaakaza 'arshuki qaalat kaanna hoo; wa ooteenal 'ilma min qablihaa wa kunnaa muslimeen", english: "So when she arrived, she was asked, \"Is this thy throne?\" She said, \"It was just like this; and knowledge was bestowed on us in advance of this, and we have submitted to Allah (in Islam)", romanUrdu: "Malika jab haazir hui to ussey kaha gaya, kya tera takht (throne) aisa hi hai? Woh kehne lagi “yeh to goya wahi hai , hum to pehle hi jaan gaye thay aur humne sar-e-itaat jhuka diya tha (ya hum muslim ho chuke thay)”" },
    { number: 43, arabic: "وَصَدَّهَا مَا كَانَت تَّعْبُدُ مِن دُونِ ٱللَّهِ ۖ إِنَّهَا كَانَتْ مِن قَوْمٍۢ كَٰفِرِينَ", transliteration: "Wasaddaha ma kanat taAAbudu min dooni Allahi innaha kanat min qawmin kafireena", transliterationB: "Wa saddahaa maa kaanat ta'budu min doonil laahi innahaa kaanat min qawmin kaafireen", english: "And he diverted her from the worship of others besides Allah: for she was (sprung) of a people that had no faith", romanUrdu: "Usko (iman laney se) jis cheez ne rok rakkha tha woh un maboodon ki ibadat thi jinhein woh Allah ke siwa poojhti thi, kyunke woh ek kafir qaum se thi" },
    { number: 44, arabic: "قِيلَ لَهَا ٱدْخُلِى ٱلصَّرْحَ ۖ فَلَمَّا رَأَتْهُ حَسِبَتْهُ لُجَّةًۭ وَكَشَفَتْ عَن سَاقَيْهَا ۚ قَالَ إِنَّهُۥ صَرْحٌۭ مُّمَرَّدٌۭ مِّن قَوَارِيرَ ۗ قَالَتْ رَبِّ إِنِّى ظَلَمْتُ نَفْسِى وَأَسْلَمْتُ مَعَ سُلَيْمَٰنَ لِلَّهِ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Qeela laha odkhulee alssarha falamma raathu hasibathu lujjatan wakashafat AAan saqayha qala innahu sarhun mumarradun min qawareera qalat rabbi innee thalamtu nafsee waaslamtu maAAa sulaymana lillahi rabbi alAAalameena", transliterationB: "Qeela lahad khulis sarha falammaa ra at hu hasibat hu lujjatanw wa khashafat 'an saaqaihaa; qaala innahoo sarhum mumarradum min qawaareer; qaalat Rabbi innee zalamtu nafsee wa aslamtu ma'a Sulaimaana lillaahi Rabbil 'aalameen", english: "She was asked to enter the lofty Palace: but when she saw it, she thought it was a lake of water, and she (tucked up her skirts), uncovering her legs. He said: \"This is but a palace paved smooth with slabs of glass.\" She said: \"O my Lord! I have indeed wronged my soul: I do (now) submit (in Islam), with Solomon, to the Lord of the Worlds", romanUrdu: "Ussey kaha gaya ke mahal mein daakhil ho, usne jo dekha to samjhi ke pani ka hauz hai aur utarne ke liye usne apne painchey utha liye (tucked up her skirt) , Sulaiman ne kaha yeh sheeshey (glass) ka chikna farsh hai ispar woh pukar utthi “Aey mere Rubb, (aaj tak) main apne nafs par bada zulm karti rahi, aur ab maine Sulaiman ke saath Allah Rabbul aalameen ki itaat qabool karli”" },
    { number: 45, arabic: "وَلَقَدْ أَرْسَلْنَآ إِلَىٰ ثَمُودَ أَخَاهُمْ صَٰلِحًا أَنِ ٱعْبُدُوا۟ ٱللَّهَ فَإِذَا هُمْ فَرِيقَانِ يَخْتَصِمُونَ", transliteration: "Walaqad arsalna ila thamooda akhahum salihan ani oAAbudoo Allaha faitha hum fareeqani yakhtasimoona", transliterationB: "Wa laqad arsalnaaa ilaa Samoda akhaahum Saalihan ani'budul lahha fa izaa hum fareeqaani yakhtasimoon", english: "We sent (aforetime), to the Thamud, their brother Salih, saying, \"Serve Allah\": But behold, they became two factions quarrelling with each other", romanUrdu: "Aur Samood ki taraf humne unke bhai Saleh ko (yeh paigaam de kar) bheja ke Allah ki bandagi karo, to yakayak woh do mutakhasim fareeq (two wrangling) ban gaye" },
    { number: 46, arabic: "قَالَ يَٰقَوْمِ لِمَ تَسْتَعْجِلُونَ بِٱلسَّيِّئَةِ قَبْلَ ٱلْحَسَنَةِ ۖ لَوْلَا تَسْتَغْفِرُونَ ٱللَّهَ لَعَلَّكُمْ تُرْحَمُونَ", transliteration: "Qala ya qawmi lima tastaAAjiloona bialssayyiati qabla alhasanati lawla tastaghfiroona Allaha laAAallakum turhamoona", transliterationB: "Qaala yaa qawmi lima tasta'jiloona bissaiyi'ati qablal hasanati law laa tas taghfiroonal laaha la'allakum turhamoon", english: "He said: \"O my people! why ask ye to hasten on the evil in preference to the good? If only ye ask Allah for forgiveness, ye may hope to receive mercy", romanUrdu: "Saleh ne kaha “aey meri qaum ke logon, bhalayi se pehle burayi ke liye kyun jaldi machate ho? Kyun nahin Allah se magfirat talab karte? Shayad ke tumpar reham farmaya jaye?”" },
    { number: 47, arabic: "قَالُوا۟ ٱطَّيَّرْنَا بِكَ وَبِمَن مَّعَكَ ۚ قَالَ طَٰٓئِرُكُمْ عِندَ ٱللَّهِ ۖ بَلْ أَنتُمْ قَوْمٌۭ تُفْتَنُونَ", transliteration: "Qaloo ittayyarna bika wabiman maAAaka qala tairukum AAinda Allahi bal antum qawmun tuftanoona", transliterationB: "Qaalut taiyarnaa bika wa bimam ma'ak; qaala taaa'irukum 'indal laahi bal antum qawmun tuftanoon", english: "They said: \"Ill omen do we augur from thee and those that are with thee\". He said: \"Your ill omen is with Allah; yea, ye are a people under trial", romanUrdu: "Unhon ne kaha “humne to tumko aur tumhare sathiyon ko badd-shaguni ka nishaan paya hai”. Saleh ne jawab diya “tumhare neik o badd shagun ka sar rishta (good and bad omens issue) Allah ke paas hai. Asal baat yeh hai ke tum logon ki aazmaish ho rahi hai”" },
    { number: 48, arabic: "وَكَانَ فِى ٱلْمَدِينَةِ تِسْعَةُ رَهْطٍۢ يُفْسِدُونَ فِى ٱلْأَرْضِ وَلَا يُصْلِحُونَ", transliteration: "Wakana fee almadeenati tisAAatu rahtin yufsidoona fee alardi wala yuslihoona", transliterationB: "Wa kaana fil madeenati tis'atu rahtiny yufsidoona fil ardi wa laa yuslihoon", english: "There were in the city nine men of a family, who made mischief in the land, and would not reform", romanUrdu: "Us shehar mein naw (nine) jatthey-daar (ring-leaders) thay jo mulk mein fasaad phaylatey aur koi islaah ka kaam na karte thay" },
    { number: 49, arabic: "قَالُوا۟ تَقَاسَمُوا۟ بِٱللَّهِ لَنُبَيِّتَنَّهُۥ وَأَهْلَهُۥ ثُمَّ لَنَقُولَنَّ لِوَلِيِّهِۦ مَا شَهِدْنَا مَهْلِكَ أَهْلِهِۦ وَإِنَّا لَصَٰدِقُونَ", transliteration: "Qaloo taqasamoo biAllahi lanubayyitannahu waahlahu thumma lanaqoolanna liwaliyyihi ma shahidna mahlika ahlihi wainna lasadiqoona", transliterationB: "Qaaloo taqaasamoo billaahi lanubaiyitannahoo wa ahlahoo summaa lanaqoolana liwaliy yihee maa shahidnaa mahlika ahliee wa innaa lasaadiqoon", english: "They said: \"Swear a mutual oath by Allah that we shall make a secret night attack on him and his people, and that we shall then say to his heir (when he seeks vengeance): 'We were not present at the slaughter of his people, and we are positively telling the truth", romanUrdu: "Unhon ne aapas mein kaha “ khuda ki kasam kha kar ahad karlo ke hum Saleh aur uske ghar walon par shabkhun (secret night attack) marenge aur phir uske wali(guardian) se keh denge ke hum us khandaan ki halakat ke mauqe par maujood na thay, hum bilkul sach kehte hain" },
    { number: 50, arabic: "وَمَكَرُوا۟ مَكْرًۭا وَمَكَرْنَا مَكْرًۭا وَهُمْ لَا يَشْعُرُونَ", transliteration: "Wamakaroo makran wamakarna makran wahum la yashAAuroona", transliterationB: "Wa makaroo makranw wa makarnaa makranw wa hum laa yash'uroon", english: "They plotted and planned, but We too planned, even while they perceived it not", romanUrdu: "Yeh chaal to woh chale aur phir ek chaal humne chali jiski unhein khabar na thi" },
    { number: 51, arabic: "فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ مَكْرِهِمْ أَنَّا دَمَّرْنَٰهُمْ وَقَوْمَهُمْ أَجْمَعِينَ", transliteration: "Faonthur kayfa kana AAaqibatu makrihim anna dammarnahum waqawmahum ajmaAAeena", transliterationB: "Fanzur kaifa kaana 'aaqibatu makrihim annaa dammar naahum wa qawmahum ajma'een", english: "Then see what was the end of their plot!- this, that We destroyed them and their people, all (of them)", romanUrdu: "Ab dekhlo ke unki chaal ka anjaam kya hua. Humne tabaah karke rakh diya unko aur unki poori qaum ko" },
    { number: 52, arabic: "فَتِلْكَ بُيُوتُهُمْ خَاوِيَةًۢ بِمَا ظَلَمُوٓا۟ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَعْلَمُونَ", transliteration: "Fatilka buyootuhum khawiyatan bima thalamoo inna fee thalika laayatan liqawmin yaAAlamoona", transliterationB: "Fatilka buyootuhum khaa wiyatam bimaa zalamoo; inna fee zaalika la Aayatal liqaw miny-ya'lamoon", english: "Now such were their houses, - in utter ruin, - because they practised wrong-doing. Verily in this is a Sign for people of knowledge", romanUrdu: "Woh unke ghar khali padey hain us zulm ki padash mein jo woh karte thay, Is mein ek nishaan e ibrat hai un logon ke liye jo ilm rakhte hain" },
    { number: 53, arabic: "وَأَنجَيْنَا ٱلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ", transliteration: "Waanjayna allatheena amanoo wakanoo yattaqoona", transliterationB: "Wa anjainal lazeena aamanoo wa kaanoo yattaqoon", english: "And We saved those who believed and practised righteousness", romanUrdu: "Aur bacha liya humne un logon ko jo iman laye thay aur nafarmani se parheiz karte thay" },
    { number: 54, arabic: "وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ أَتَأْتُونَ ٱلْفَٰحِشَةَ وَأَنتُمْ تُبْصِرُونَ", transliteration: "Walootan ith qala liqawmihi atatoona alfahishata waantum tubsiroona", transliterationB: "Wa lootan iz qaala liqawmiheee ataatoonal faa hishata wa antum qawmun tajjhaloon", english: "(We also sent) Lut (as a messenger): behold, He said to his people, \"Do ye do what is shameful though ye see (its iniquity)", romanUrdu: "Aur Lut ko humne bheja. Yaad karo woh waqt jab usne apni qaum se kaha “kya tum aankhon dekhte badhkari karte ho" },
    { number: 55, arabic: "أَئِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ شَهْوَةًۭ مِّن دُونِ ٱلنِّسَآءِ ۚ بَلْ أَنتُمْ قَوْمٌۭ تَجْهَلُونَ", transliteration: "Ainnakum latatoona alrrijala shahwatan min dooni alnnisai bal antum qawmun tajhaloona", transliterationB: "A'innakum lataatoonar rijaala shahwatam min doonin nisaaa'; bal antum qawmun tajhaloon", english: "Would ye really approach men in your lusts rather than women? Nay, ye are a people (grossly) ignorant", romanUrdu: "Kya tumhara yahi chalan hai ke auraton ko chodh kar mardon ke paas shehwat-rani (sexual desire) ke liye jatey ho? Haqeeqat yeh hai ke tumlog sakht jahalat(ignorance) ka kaam karte ho.”" },
    { number: 56, arabic: "۞ فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوٓا۟ أَخْرِجُوٓا۟ ءَالَ لُوطٍۢ مِّن قَرْيَتِكُمْ ۖ إِنَّهُمْ أُنَاسٌۭ يَتَطَهَّرُونَ", transliteration: "Fama kana jawaba qawmihi illa an qaloo akhrijoo ala lootin min qaryatikum innahum onasun yatatahharoona", transliterationB: "Fammaa kaana jawaaba qawmiheee illaaa an qaalooo akrijoon aalaa Lootim min qaryatikum innahum unaasuny yatatahharoon", english: "But his people gave no other answer but this: they said, \"Drive out the followers of Lut from your city: these are indeed men who want to be clean and pure", romanUrdu: "Magar uski qaum ka jawab iske siwa kuch na tha ke unhon ne kaha “ nikaal do Lut ke ghar walon ko apni basti se, yeh baday paakbaaz bante hain”" },
    { number: 57, arabic: "فَأَنجَيْنَٰهُ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ قَدَّرْنَٰهَا مِنَ ٱلْغَٰبِرِينَ", transliteration: "Faanjaynahu waahlahu illa imraatahu qaddarnaha mina alghabireena", transliterationB: "Fa anjainaahu wa ahlahooo illam ra atahoo qaddarnaahaa minal ghaabireen", english: "But We saved him and his family, except his wife; her We destined to be of those who lagged behind", romanUrdu: "Aakhir e kaar humne bacha liya usko aur uske ghar walon ko, bajuz uski biwi ke jiska peechey reh jana humne tai kardiya tha" },
    { number: 58, arabic: "وَأَمْطَرْنَا عَلَيْهِم مَّطَرًۭا ۖ فَسَآءَ مَطَرُ ٱلْمُنذَرِينَ", transliteration: "Waamtarna AAalayhim mataran fasaa mataru almunthareena", transliterationB: "Wa amtarnaa 'alaihimm mataran fasaaa'a matarul munzareen", english: "And We rained down on them a shower (of brimstone): and evil was the shower on those who were admonished (but heeded not)", romanUrdu: "Aur barsayi un logon par ek barsaat, bahut hi buri barsaat thi wo un logon ke haqq mein jo mutanabbeh kiye jaa chuke thay" },
    { number: 59, arabic: "قُلِ ٱلْحَمْدُ لِلَّهِ وَسَلَٰمٌ عَلَىٰ عِبَادِهِ ٱلَّذِينَ ٱصْطَفَىٰٓ ۗ ءَآللَّهُ خَيْرٌ أَمَّا يُشْرِكُونَ", transliteration: "Quli alhamdu lillahi wasalamun AAala AAibadihi allatheena istafa allahu khayrun amma yushrikoona", transliterationB: "Qulil hamdu lillaahi wa salaamun 'alaa 'ibaadihil lazeenas tafaa; aaallaahu khairun ammmaa yushrikoon", english: "Say: Praise be to Allah, and Peace on his servants whom He has chosen (for his Message). (Who) is better?- Allah or the false gods they associate (with Him)", romanUrdu: "(Aey Nabi) kaho, hamd hai Allah ke liye aur salaam uske un bandon par jinhein usne barguzida kiya. (Insey pucho) Allah behtar hai ya woh mabood jinhein yeh log iska shareek bana rahey hain" },
    { number: 60, arabic: "أَمَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَأَنزَلَ لَكُم مِّنَ ٱلسَّمَآءِ مَآءًۭ فَأَنۢبَتْنَا بِهِۦ حَدَآئِقَ ذَاتَ بَهْجَةٍۢ مَّا كَانَ لَكُمْ أَن تُنۢبِتُوا۟ شَجَرَهَآ ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ بَلْ هُمْ قَوْمٌۭ يَعْدِلُونَ", transliteration: "Amman khalaqa alssamawati waalarda waanzala lakum mina alssamai maan faanbatna bihi hadaiqa thata bahjatin ma kana lakum an tunbitoo shajaraha ailahun maAAa Allahi bal hum qawmun yaAAdiloona", transliterationB: "Amman khalaqas samaawaati wal arda wa anzala lakum minas samaaa'i maaa'an fa ambatnaa bihee hadaaa'iqa zaata bahjjah; maa kanna lakum an tumbitoo shajarahaa; 'a-ilaahum ma'al laah; bal hum qawmuny ya'diloon", english: "Or, Who has created the heavens and the earth, and Who sends you down rain from the sky? Yea, with it We cause to grow well-planted orchards full of beauty of delight: it is not in your power to cause the growth of the trees in them. (Can there be another) god besides Allah? Nay, they are a people who swerve from justice", romanUrdu: "Bhala woh kaun hai jisne aasmano aur zameen ko paida kiya, aur tumhare liye aasmaan se pani barsaya, phir uske zariye se woh khusnuma baagh ugaye jinke darakhton ka ugana tumhare bas mein na tha? Kya Allah ke saath koi dusra khuda bhi (in kaamon mein shareek) hai? (Nahin), balke yahi log raah e raast se hatkar chale jaa rahe hain" },
    { number: 61, arabic: "أَمَّن جَعَلَ ٱلْأَرْضَ قَرَارًۭا وَجَعَلَ خِلَٰلَهَآ أَنْهَٰرًۭا وَجَعَلَ لَهَا رَوَٰسِىَ وَجَعَلَ بَيْنَ ٱلْبَحْرَيْنِ حَاجِزًا ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ", transliteration: "Amman jaAAala alarda qararan wajaAAala khilalaha anharan wajaAAala laha rawasiya wajaAAala bayna albahrayni hajizan ailahun maAAa Allahi bal aktharuhum la yaAAlamoona", transliterationB: "Ammann ja'alal arda qaraaranw wa ja'ala khilaalahaaa anhaaranw wa ja'ala lahaa rawaasiya wa ja'ala bainal bahraini haajizaa; 'a-ilaahumma'allah; bal aksaruhum la ya'lamoon", english: "Or, Who has made the earth firm to live in; made rivers in its midst; set thereon mountains immovable; and made a separating bar between the two bodies of flowing water? (can there be another) god besides Allah? Nay, most of them know not", romanUrdu: "Aur woh kaun hai jisne zameen ko jaye qaraar banaya aur uske andar dariya rawan kiye, aur usmein (pahadon ki) mekhein gaadh di aur pani ke do zakhiron(two bodies) ke darmiyan purda hayal kardiye? Kya Allah ke saath koi aur khuda bhi (in kaamon mein shareek) hai? Nahin, balke in mein se aksar log nadaan hain" },
    { number: 62, arabic: "أَمَّن يُجِيبُ ٱلْمُضْطَرَّ إِذَا دَعَاهُ وَيَكْشِفُ ٱلسُّوٓءَ وَيَجْعَلُكُمْ خُلَفَآءَ ٱلْأَرْضِ ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ قَلِيلًۭا مَّا تَذَكَّرُونَ", transliteration: "Amman yujeebu almudtarra itha daAAahu wayakshifu alssooa wayajAAalukum khulafaa alardi ailahun maAAa Allahi qaleelan ma tathakkaroona", transliterationB: "Ammany-yujeebul mud tarra izaa da'aahu wa yakshifussooo'a wa yaj'alukum khula faaa'al ardi 'a-ilaahum ma'al laahi qaleelam maa tazak karoon", english: "Or, Who listens to the (soul) distressed when it calls on Him, and Who relieves its suffering, and makes you (mankind) inheritors of the earth? (Can there be another) god besides Allah? Little it is that ye heed", romanUrdu: "Kaun hai jo bekarar ki dua sunta hai jabke woh usey pukare aur kaun uski takleef rafaa karta hai? Aur (kaun hai jo) tumhein zameen ka khalifa banata hai? Kya Allah ke saath koi aur khuda bhi (yeh kaam karne wala) hai? Tum log kam hi sochte ho" },
    { number: 63, arabic: "أَمَّن يَهْدِيكُمْ فِى ظُلُمَٰتِ ٱلْبَرِّ وَٱلْبَحْرِ وَمَن يُرْسِلُ ٱلرِّيَٰحَ بُشْرًۢا بَيْنَ يَدَىْ رَحْمَتِهِۦٓ ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ تَعَٰلَى ٱللَّهُ عَمَّا يُشْرِكُونَ", transliteration: "Amman yahdeekum fee thulumati albarri waalbahri waman yursilu alrriyaha bushran bayna yaday rahmatihi ailahun maAAa Allahi taAAala Allahu AAamma yushrikoona", transliterationB: "Ammany-yahdeekum fee zulumaatil barri wal bahri wa many yursilu riyaaha bushram baina yadai rahmatih; 'a-ilaahum ma'al laah; Ta'aalal laahu 'ammaa yushrikoon", english: "Or, Who guides you through the depths of darkness on land and sea, and Who sends the winds as heralds of glad tidings, going before His Mercy? (Can there be another) god besides Allah?- High is Allah above what they associate with Him", romanUrdu: "Aur woh kaun hai jo khushki aur samandar ki tareekiyon (darkness) mein tumko raasta dikhata hai aur kaun apni rehmat ke aagey hawaon ko khush khabri lekar bhejhta hai? Kya Allah ke saath koi dusra khuda bhi (yeh kaam karta) hai? Bahut baala o bartar hai Allah us shirk se jo yeh log karte hain" },
    { number: 64, arabic: "أَمَّن يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ وَمَن يَرْزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ قُلْ هَاتُوا۟ بُرْهَٰنَكُمْ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Amman yabdao alkhalqa thumma yuAAeeduhu waman yarzuqukum mina alssamai waalardi ailahun maAAa Allahi qul hatoo burhanakum in kuntum sadiqeena", transliterationB: "Ammmany-yabda'ul khalqa summa yu'eeduhoo wa many-yarzuqukum minas sammaaa'i wal ard; 'a-ilaahum ma'allah; qul haatoo burhaanakum in kuntum saadiqeen", english: "Or, Who originates creation, then repeats it, and who gives you sustenance from heaven and earth? (Can there be another) god besides Allah? Say, \"Bring forth your argument, if ye are telling the truth", romanUrdu: "Aur woh kaun hai jo khalq (creation) ki ibtida (orignate) karta aur phir uska iaada (reproduce) karta hai. Aur kaun tumko aasmaan aur zameen se rizq deta hai? Kya Allah ke saath koi aur khuda bhi (in kaamon mein hissedar) hai? Kaho ke laao apni daleel agar tum sachhey ho" },
    { number: 65, arabic: "قُل لَّا يَعْلَمُ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ٱلْغَيْبَ إِلَّا ٱللَّهُ ۚ وَمَا يَشْعُرُونَ أَيَّانَ يُبْعَثُونَ", transliteration: "Qul la yaAAlamu man fee alssamawati waalardi alghayba illa Allahu wama yashAAuroona ayyana yubAAathoona", transliterationB: "Qul laa ya'lamu mman fis sammaawaati wal ardil ghaiba illal laah; wa maa yash'uroona aiyaana yub'asoon", english: "Say: None in the heavens or on earth, except Allah, knows what is hidden: nor can they perceive when they shall be raised up (for Judgment)", romanUrdu: "Inse kaho, Allah ke siwa aasmano aur zameen mein koi gaib ka ilam nahin rakhta, aur woh nahin jaante ke kab woh uthaye jayenge" },
    { number: 66, arabic: "بَلِ ٱدَّٰرَكَ عِلْمُهُمْ فِى ٱلْءَاخِرَةِ ۚ بَلْ هُمْ فِى شَكٍّۢ مِّنْهَا ۖ بَلْ هُم مِّنْهَا عَمُونَ", transliteration: "Bali iddaraka AAilmuhum fee alakhirati bal hum fee shakkin minha bal hum minha AAamoona", transliterationB: "Balid daaraka 'ilmuhum fil Aakhirah; bal hum fee shakkim minhaa bal hum minhaa 'amoon", english: "Still less can their knowledge comprehend the Hereafter: Nay, they are in doubt and uncertainty thereanent; nay, they are blind thereunto", romanUrdu: "Balke aakhirat ka to ilam hi in logon se ghum ho gaya hai, balke yeh uski taraf se shakk mein hain, balke yeh ussey andhey hain" },
    { number: 67, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوٓا۟ أَءِذَا كُنَّا تُرَٰبًۭا وَءَابَآؤُنَآ أَئِنَّا لَمُخْرَجُونَ", transliteration: "Waqala allatheena kafaroo aitha kunna turaban waabaona ainna lamukhrajoona", transliterationB: "Wa qaalal lazeena kafarooo 'a-izaa kunnaa turaabanw wa aabaaa'unaaa a'innaa lamukhrajoon", english: "The Unbelievers say: \"What! when we become dust,- we and our fathers,- shall we really be raised (from the dead)", romanUrdu: "Yeh munkireen kehte hain “kya jab hum aur hamare baap dada mitti ho chuke honge to humein waqayi qabaron se nikala jayega?”" },
    { number: 68, arabic: "لَقَدْ وُعِدْنَا هَٰذَا نَحْنُ وَءَابَآؤُنَا مِن قَبْلُ إِنْ هَٰذَآ إِلَّآ أَسَٰطِيرُ ٱلْأَوَّلِينَ", transliteration: "Laqad wuAAidna hatha nahnu waabaona min qablu in hatha illa asateeru alawwaleena", transliterationB: "Laqad wu'idnaa haazaa nahnu wa aabaaa'unaa min qablu in haazaaa illaaa asaateerul awwaleen", english: "It is true we were promised this,- we and our fathers before (us): these are nothing but tales of the ancients", romanUrdu: "Yeh khabrein humko bhi bahut di gayi hain aur pehle hamare aabaa o ajdaad ko bhi di jaati rahi hain, magar yeh bas afsane hi afsane hain jo agle waqton se sunte chale aa rahey hain”" },
    { number: 69, arabic: "قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُجْرِمِينَ", transliteration: "Qul seeroo fee alardi faonthuroo kayfa kana AAaqibatu almujrimeena", transliterationB: "Qul seeroo fil ardi fanzuroo kaifa kaana 'aaqibatul mujremeen", english: "Say: \"Go ye through the earth and see what has been the end of those guilty (of sin)", romanUrdu: "Kaho, zara zameen mein chal phir kar dekho ke mujreemo ka kya anjaam ho chuka hai" },
    { number: 70, arabic: "وَلَا تَحْزَنْ عَلَيْهِمْ وَلَا تَكُن فِى ضَيْقٍۢ مِّمَّا يَمْكُرُونَ", transliteration: "Wala tahzan AAalayhim wala takun fee dayqin mimma yamkuroona", transliterationB: "Wa laa tahzan 'alaihim wa laa takun fee daiqim mimmaa yamkuroon", english: "But grieve not over them, nor distress thyself because of their plots", romanUrdu: "(Aey Nabi), inke haal par ranjh na karo aur na inki chaalon par dil tangg ho" },
    { number: 71, arabic: "وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Wayaqooloona mata hatha alwaAAdu in kuntum sadiqeena", transliterationB: "Wa yaqooloona mataa haazal wa'du in kuntum saadiqeen", english: "They also say: \"When will this promise (come to pass)? (Say) if ye are truthful", romanUrdu: "Woh kehte hain ke “yeh dhamki kab poori hogi agar tum sacchey ho?”" },
    { number: 72, arabic: "قُلْ عَسَىٰٓ أَن يَكُونَ رَدِفَ لَكُم بَعْضُ ٱلَّذِى تَسْتَعْجِلُونَ", transliteration: "Qul AAasa an yakoona radifa lakum baAAdu allathee tastaAAjiloona", transliterationB: "Qul 'asaaa any-yakoona radifa lakum ba'dul lazee tasta'jiloon", english: "Say: \"It may be that some of the events which ye wish to hasten on may be (close) in your pursuit", romanUrdu: "Kaho, kya ajab ke jis azaab ke liye tum jaldi macha rahey ho uska ek hissa tumhare qareeb hi aa laga ho" },
    { number: 73, arabic: "وَإِنَّ رَبَّكَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَشْكُرُونَ", transliteration: "Wainna rabbaka lathoo fadlin AAala alnnasi walakinna aktharahum la yashkuroona", transliterationB: "Wa innna Rabbaka lazoo fadlin 'alan naasi wa laakina aksarahum laa yashkuroon", english: "But verily thy Lord is full of grace to mankind: Yet most of them are ungrateful", romanUrdu: "Haqeeqat yeh hai ke tera Rubb to logon par bada fazal farmane wala hai, magar aksar log shukar nahin karte" },
    { number: 74, arabic: "وَإِنَّ رَبَّكَ لَيَعْلَمُ مَا تُكِنُّ صُدُورُهُمْ وَمَا يُعْلِنُونَ", transliteration: "Wainna rabbaka layaAAlamu ma tukinnu sudooruhum wama yuAAlinoona", transliterationB: "Wa inna Rabbaka la ya'lamu maa tukinnu sudooruhum wa maa yu'linoon", english: "And verily thy Lord knoweth all that their hearts do hide. As well as all that they reveal", romanUrdu: "Bila shubha tera Rubb khoob jaanta hai jo kuch unke seenay apne andar chupaye huey hain aur jo kuch woh zaahir karte hain" },
    { number: 75, arabic: "وَمَا مِنْ غَآئِبَةٍۢ فِى ٱلسَّمَآءِ وَٱلْأَرْضِ إِلَّا فِى كِتَٰبٍۢ مُّبِينٍ", transliteration: "Wama min ghaibatin fee alssamai waalardi illa fee kitabin mubeenin", transliterationB: "Wa maa min ghaaa'ibatin fis samaaa'i wal ardi illaa fee kitaabimm mubeen", english: "Nor is there aught of the unseen, in heaven or earth, but is (recorded) in a clear record", romanUrdu: "Aasmaan o zameen ki koi posheeda cheez aisi nahin hai jo ek wazeh kitaab mein likhi hui maujood na ho" },
    { number: 76, arabic: "إِنَّ هَٰذَا ٱلْقُرْءَانَ يَقُصُّ عَلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ أَكْثَرَ ٱلَّذِى هُمْ فِيهِ يَخْتَلِفُونَ", transliteration: "Inna hatha alqurana yaqussu AAala banee israeela akthara allathee hum feehi yakhtalifoona", transliterationB: "Inna haazal Qur-aana yaqussu 'alaa Baneee israaa'eela aksaral lazee hum feehi yakhtalifoon", english: "Verily this Qur'an doth explain to the Children of Israel most of the matters in which they disagree", romanUrdu: "Yeh waqia hai ke yeh Quraan bani Israel ko aksar un baaton ki haqeeqat batata hai jin mein woh ikhtilaf rakhte hain" },
    { number: 77, arabic: "وَإِنَّهُۥ لَهُدًۭى وَرَحْمَةٌۭ لِّلْمُؤْمِنِينَ", transliteration: "Wainnahu lahudan warahmatun lilmumineena", transliterationB: "Wa innahoo lahudanw wa rahmatul lilmu'mineen", english: "And it certainly is a Guide and a Mercy to those who believe", romanUrdu: "Aur yeh hidayat aur rehmat hai iman laney walon ke liye" },
    { number: 78, arabic: "إِنَّ رَبَّكَ يَقْضِى بَيْنَهُم بِحُكْمِهِۦ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْعَلِيمُ", transliteration: "Inna rabbaka yaqdee baynahum bihukmihi wahuwa alAAazeezu alAAaleemu", transliterationB: "Inna Rabbaka yaqdee bainahum bihukmih; wa Huwal 'Azeezul 'Aleem", english: "Verily thy Lord will decide between them by His Decree: and He is Exalted in Might, All-Knowing", romanUrdu: "Yaqeenan (isi tarah) tera Rubb in logon ke darmiyan bhi apne hukum se faisla kardega. Aur woh zabardast aur sab kuch jaan-nay wala hai" },
    { number: 79, arabic: "فَتَوَكَّلْ عَلَى ٱللَّهِ ۖ إِنَّكَ عَلَى ٱلْحَقِّ ٱلْمُبِينِ", transliteration: "Fatawakkal AAala Allahi innaka AAala alhaqqi almubeeni", transliterationB: "Fatawakkal 'alal laahi innaka 'alal haqqil mubeen", english: "So put thy trust in Allah: for thou art on (the path of) manifest Truth", romanUrdu: "Pas aey Nabi, Allah par bharosa rakkho, yaqeenan tum sareeh haqq par ho" },
    { number: 80, arabic: "إِنَّكَ لَا تُسْمِعُ ٱلْمَوْتَىٰ وَلَا تُسْمِعُ ٱلصُّمَّ ٱلدُّعَآءَ إِذَا وَلَّوْا۟ مُدْبِرِينَ", transliteration: "Innaka la tusmiAAu almawta wala tusmiAAu alssumma aldduAAaa itha wallaw mudbireena", transliterationB: "Innaka laa tusmi'ul mawtaa wa laa tusmi'us summad du'aaa izaa wallaw mudbireen", english: "Truly thou canst not cause the dead to listen, nor canst thou cause the deaf to hear the call, (especially) when they turn back in retreat", romanUrdu: "Tum murdon ko nahin suna sakte, na un behron tak apni pukar pahuncha sakte ho jo peeth phair kar bhaagey ja rahey hon" },
    { number: 81, arabic: "وَمَآ أَنتَ بِهَٰدِى ٱلْعُمْىِ عَن ضَلَٰلَتِهِمْ ۖ إِن تُسْمِعُ إِلَّا مَن يُؤْمِنُ بِـَٔايَٰتِنَا فَهُم مُّسْلِمُونَ", transliteration: "Wama anta bihadee alAAumyi AAan dalalatihim in tusmiAAu illa man yuminu biayatina fahum muslimoona", transliterationB: "Wa maaa anta bihaadil 'umyi 'an dalaalatihim in tusmi'u illaa mai yu'minu bi aayaatinaa fahum muslimoon", english: "Nor canst thou be a guide to the blind, (to prevent them) from straying: only those wilt thou get to listen who believe in Our Signs, and they will bow in Islam", romanUrdu: "Aur na andhon ko raasta bata kar bhatakne se bacha sakte ho. Tum to apni baat unhi logon ko suna sakte ho jo hamari aayat par iman latey hain aur phir farmabardaar ban jatey hain" },
    { number: 82, arabic: "۞ وَإِذَا وَقَعَ ٱلْقَوْلُ عَلَيْهِمْ أَخْرَجْنَا لَهُمْ دَآبَّةًۭ مِّنَ ٱلْأَرْضِ تُكَلِّمُهُمْ أَنَّ ٱلنَّاسَ كَانُوا۟ بِـَٔايَٰتِنَا لَا يُوقِنُونَ", transliteration: "Waitha waqaAAa alqawlu AAalayhim akhrajna lahum dabbatan mina alardi tukallimuhum anna alnnasa kanoo biayatina la yooqinoona", transliterationB: "Wa izaa waqa'al qawhu 'alaihim akhrajnaa lahum daabbatam minal ardi tukal limuhum annan naasa kaanoo bi aayaatinaa laa yooqinoon", english: "And when the Word is fulfilled against them (the unjust), we shall produce from the earth a beast to (face) them: He will speak to them, for that mankind did not believe with assurance in Our Signs", romanUrdu: "Aur jab hamari baat poori hone ka waqt unpar aa pahunchega to hum unke liye ek jaanwar zameen se nikalenge jo unse kalaam karega ke log hamari aayat par yaqeen nahin karte thay" },
    { number: 83, arabic: "وَيَوْمَ نَحْشُرُ مِن كُلِّ أُمَّةٍۢ فَوْجًۭا مِّمَّن يُكَذِّبُ بِـَٔايَٰتِنَا فَهُمْ يُوزَعُونَ", transliteration: "Wayawma nahshuru min kulli ommatin fawjan mimman yukaththibu biayatina fahum yoozaAAoona", transliterationB: "Wa Yawma nahshuru min kulli ummmatin fawjam mim many-yukazzibu bi Aayaatinaa fahum yooza'oon", english: "One day We shall gather together from every people a troop of those who reject our Signs, and they shall be kept in ranks", romanUrdu: "Aur zara tasavvur karo us din ka jab hum har ummat mein se ek fauj ki fauj un logon ki gher layenge jo hamari aayat ko jhutlaya karte thay, phir unko (unki aqsaam (classification and merit) ke lihaz se darja ba darja) murattab (arrange) kiya jayega" },
    { number: 84, arabic: "حَتَّىٰٓ إِذَا جَآءُو قَالَ أَكَذَّبْتُم بِـَٔايَٰتِى وَلَمْ تُحِيطُوا۟ بِهَا عِلْمًا أَمَّاذَا كُنتُمْ تَعْمَلُونَ", transliteration: "Hatta itha jaoo qala akaththabtum biayatee walam tuheetoo biha AAilman ammatha kuntum taAAmaloona", transliterationB: "Hattaaa izaa jaaa'oo qaala akazzabtum bi Aayaatee wa lam tuheetoo bihaa 'ilman ammaazaa kuntum ta'maloon", english: "Until, when they come (before the Judgment-seat), (Allah) will say: \"Did ye reject My Signs, though ye comprehended them not in knowledge, or what was it ye did", romanUrdu: "Yahan tak ke jab sab aa jayenge to (unka Rubb unse) puchega ke “tumne meri aayat ko jhutla diya halaanke tumne unka ilmi ihata (comprehend) na kiya tha? Agar yeh nahin to aur tum kya kar rahey thay?”" },
    { number: 85, arabic: "وَوَقَعَ ٱلْقَوْلُ عَلَيْهِم بِمَا ظَلَمُوا۟ فَهُمْ لَا يَنطِقُونَ", transliteration: "WawaqaAAa alqawlu AAalayhim bima thalamoo fahum la yantiqoona", transliterationB: "Wa waqa'al qawlu 'alaihim bimaa zalamoo fahum laa yantiqoon", english: "And the Word will be fulfilled against them, because of their wrong-doing, and they will be unable to speak (in plea)", romanUrdu: "Aur unke zulm ki wajah se azaab ka wada unpar poora ho jayega, tab woh kuch bhi na bol sakenge" },
    { number: 86, arabic: "أَلَمْ يَرَوْا۟ أَنَّا جَعَلْنَا ٱلَّيْلَ لِيَسْكُنُوا۟ فِيهِ وَٱلنَّهَارَ مُبْصِرًا ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Alam yaraw anna jaAAalna allayla liyaskunoo feehi waalnnahara mubsiran inna fee thalika laayatin liqawmin yuminoona", transliterationB: "Alam yaraw annaa ja'alnal laila li yaskunoo feehi wannahaara mubsiraa; inna fee zaalika la Aayaatil liqaw miny-yu'minoon", english: "See they not that We have made the Night for them to rest in and the Day to give them light? Verily in this are Signs for any people that believe", romanUrdu: "Kya unko soojhayi na deta tha ke humne raat unke liye sukoon haasil karne ko banayi thi aur din ko roshan kiya tha? Isi mein bahut nishaniyan thi un logon ke liye jo iman latey thay" },
    { number: 87, arabic: "وَيَوْمَ يُنفَخُ فِى ٱلصُّورِ فَفَزِعَ مَن فِى ٱلسَّمَٰوَٰتِ وَمَن فِى ٱلْأَرْضِ إِلَّا مَن شَآءَ ٱللَّهُ ۚ وَكُلٌّ أَتَوْهُ دَٰخِرِينَ", transliteration: "Wayawma yunfakhu fee alssoori fafaziAAa man fee alssamawati waman fee alardi illa man shaa Allahu wakullun atawhu dakhireena", transliterationB: "Wa Yawma yunfakhu fis Soori fafazi'a man fis samaawaati wa man fil ardi illaa man shaaa'al laah; wa kullun atawhu daakhireen", english: "And the Day that the Trumpet will be sounded - then will be smitten with terror those who are in the heavens, and those who are on earth, except such as Allah will please (to exempt): and all shall come to His (Presence) as beings conscious of their lowliness", romanUrdu: "Aur kya guzregi us roz jabke sur/soor (trumphet) phunka jaayega aur haul(terror) kha jayenge woh sab jo aasmaano aur zameen mein hain, siwaye un logon ke jinhein Allah is haul(terror) se bachana chahega. Aur sab kaan dabaye uske huzoor hazir ho jayenge" },
    { number: 88, arabic: "وَتَرَى ٱلْجِبَالَ تَحْسَبُهَا جَامِدَةًۭ وَهِىَ تَمُرُّ مَرَّ ٱلسَّحَابِ ۚ صُنْعَ ٱللَّهِ ٱلَّذِىٓ أَتْقَنَ كُلَّ شَىْءٍ ۚ إِنَّهُۥ خَبِيرٌۢ بِمَا تَفْعَلُونَ", transliteration: "Watara aljibala tahsabuha jamidatan wahiya tamurru marra alssahabi sunAAa Allahi allathee atqana kulla shayin innahu khabeerun bima tafAAaloona", transliterationB: "Wa taral jibaala tahsabuhaa jaamidatanw wa hiya tamurru marras sahaab; sun'al laahil lazeee atqana kulla shai'; innahoo khabeerum bimaa taf'aloon", english: "Thou seest the mountains and thinkest them firmly fixed: but they shall pass away as the clouds pass away: (such is) the artistry of Allah, who disposes of all things in perfect order: for he is well acquainted with all that ye do", romanUrdu: "Aaj tu pahadon ko dekhta hai aur samajhta hai ke khoob jamey huey hain, magar us waqt yeh baadalon ki tarah udh rahey honge, yeh Allah ki qudrat ka karishma hoga jisne har cheez ko hikmat ke saath ustwar (ordered with wisdom) kiya hai. Woh khoob jaanta hai ke tumlog kya karte ho" },
    { number: 89, arabic: "مَن جَآءَ بِٱلْحَسَنَةِ فَلَهُۥ خَيْرٌۭ مِّنْهَا وَهُم مِّن فَزَعٍۢ يَوْمَئِذٍ ءَامِنُونَ", transliteration: "Man jaa bialhasanati falahu khayrun minha wahum min fazaAAin yawmaithin aminoona", transliterationB: "Man jaaa'a bilhasanati falahoo khairum minhaa wa hum min faza'iny Yawma'izin aaminoon", english: "If any do good, good will (accrue) to them therefrom; and they will be secure from terror that Day", romanUrdu: "Jo shaks bhalayi lekar aayega usey ussey zyada behtar sila milega aur aisey log us din ke haul (terror/dehshat) se mehfooz hongey" },
    { number: 90, arabic: "وَمَن جَآءَ بِٱلسَّيِّئَةِ فَكُبَّتْ وُجُوهُهُمْ فِى ٱلنَّارِ هَلْ تُجْزَوْنَ إِلَّا مَا كُنتُمْ تَعْمَلُونَ", transliteration: "Waman jaa bialssayyiati fakubbat wujoohuhum fee alnnari hal tujzawna illa ma kuntum taAAmaloona", transliterationB: "Wa man jaaa'a bissai yi'ati fakubbat wujoohuhum fin Naari hal tujzawna illaa maa kuntum ta'maloon", english: "And if any do evil, their faces will be thrown headlong into the Fire: \"Do ye receive a reward other than that which ye have earned by your deeds", romanUrdu: "Aur jo burayi liye huey aayega, aisey sab log aundhey mooh aag mein phenke jayenge. Kya tumlog iske siwa koi aur jaza paa sakte ho ke jaisa karo waisa bharo" },
    { number: 91, arabic: "إِنَّمَآ أُمِرْتُ أَنْ أَعْبُدَ رَبَّ هَٰذِهِ ٱلْبَلْدَةِ ٱلَّذِى حَرَّمَهَا وَلَهُۥ كُلُّ شَىْءٍۢ ۖ وَأُمِرْتُ أَنْ أَكُونَ مِنَ ٱلْمُسْلِمِينَ", transliteration: "Innama omirtu an aAAbuda rabba hathihi albaldati allathee harramaha walahu kullu shayin waomirtu an akoona mina almuslimeena", transliterationB: "Innamaaa umirtu an a'buda Rabba haazihil baldatil lazee harramahaa wa lahoo kullu shai'inw wa umirtu an akoona minal muslimeen", english: "For me, I have been commanded to serve the Lord of this city, Him Who has sanctified it and to Whom (belong) all things: and I am commanded to be of those who bow in Islam to Allah's Will", romanUrdu: "(Aey Muhammad, Insey kaho) “Mujhey to yahi hukum diya gaya hai ke is shehar ke Rubb ki bandagi karoon jisne isey haram (sacred) banaya hai, aur jo har cheez ka maalik hai. Mujhey hukum diya gaya hai ke main Muslim ban kar rahoon" },
    { number: 92, arabic: "وَأَنْ أَتْلُوَا۟ ٱلْقُرْءَانَ ۖ فَمَنِ ٱهْتَدَىٰ فَإِنَّمَا يَهْتَدِى لِنَفْسِهِۦ ۖ وَمَن ضَلَّ فَقُلْ إِنَّمَآ أَنَا۠ مِنَ ٱلْمُنذِرِينَ", transliteration: "Waan atluwa alqurana famani ihtada fainnama yahtadee linafsihi waman dalla faqul innama ana mina almunthireena", transliterationB: "Wa an atluwal Qur-aana famanih tadaa fa innnamaa yahtadee linafsihee wa man dalla faqul innamaaa ana minal munzireen", english: "And to rehearse the Qur'an: and if any accept guidance, they do it for the good of their own souls, and if any stray, say: \"I am only a Warner", romanUrdu: "Aur yeh Quran padh kar sunaoon” ab jo hidayat ikhtiyar karega woh apne hi bhale ke liye hidayat ikhtiyar karega, aur jo gumraah ho ussey kehdo main to bas khabardaar kardene wala hoon" },
    { number: 93, arabic: "وَقُلِ ٱلْحَمْدُ لِلَّهِ سَيُرِيكُمْ ءَايَٰتِهِۦ فَتَعْرِفُونَهَا ۚ وَمَا رَبُّكَ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", transliteration: "Waquli alhamdu lillahi sayureekum ayatihi fataAArifoonaha wama rabbuka bighafilin AAamma taAAmaloona", transliterationB: "Wa qulil hamdu lillaahi sa yureekum Aayaatihee fata'ri foonahaa; wa maa Rabbuka bighaaflin 'ammaa ta'maloon", english: "And say: \"Praise be to Allah, Who will soon show you His Signs, so that ye shall know them\"; and thy Lord is not unmindful of all that ye do", romanUrdu: "Insey kaho, tareef Allah hi ke liye hai, ankareeb woh tumhein apni nishaniyan dikha dega aur tum unhein pehchan logey, aur tera Rubb bay-khabar nahin hai un aamal se jo tum log karte ho" }
  ]
};
